import numpy as np

def efficient_binary_td_update(initial_weights: list, transitions: list, alpha: float, gamma: float) -> np.ndarray:
    weights = list(initial_weights)

    for active_s, reward, active_s_next, done in transitions:
        # V(s) = sum of weights at active feature indices
        v_s = sum(weights[i] for i in active_s)

        # V(s') = 0 if terminal, otherwise sum over next active indices
        if done or len(active_s_next) == 0:
            v_s_next = 0.0
        else:
            v_s_next = sum(weights[i] for i in active_s_next)

        # TD error: delta = r + gamma * V(s') - V(s)
        delta = reward + gamma * v_s_next - v_s

        # Semi-gradient update: only touch weights at active indices of current state
        for i in active_s:
            weights[i] += alpha * delta

    return np.array(weights)
